class ParkingSystem {

    private int[] slots;

    public ParkingSystem(int big, int medium, int small) {
        slots = new int[] {big, medium, small};
    }

    public boolean addCar(int carType) {
        if (carType == 1 && slots[0] > 0) {
            slots[0]--;
            return true;
        } else if (carType == 2 && slots[1] > 0) {
            slots[1]--;
            return true;
        } else if (carType == 3 && slots[2] > 0) {
            slots[2]--;
            return true;
        }
        return false;
    }
}
